function solve(prices, strategy, k) {
  const n = prices.length;
  let original_profit = 0;
  for (let i = 0; i < n; i++) {
    original_profit += strategy[i] * prices[i];
  }

  const prefix_prices = new Array(n + 1).fill(0);
  const prefix_strategy = new Array(n + 1).fill(0);

  for (let i = 0; i < n; i++) {
    prefix_prices[i + 1] = prefix_prices[i] + prices[i];
    prefix_strategy[i + 1] = prefix_strategy[i] + strategy[i] * prices[i];
  }

  let max_gain = 0;
  const half = k / 2;

  for (let i = 0; i <= n - k; i++) {
    const original = prefix_strategy[i + k] - prefix_strategy[i];
    const start_second = i + half;
    const end_second = i + k;
    const sum_second = prefix_prices[end_second] - prefix_prices[start_second];
    const gain = sum_second - original;
    if (gain > max_gain) {
      max_gain = gain;
    }
  }

  return original_profit + Math.max(max_gain, 0);
}
