```javascript
function solve(prices, strategy, k) {
  const n = prices.length;
  let originalProfit = 0;
  for (let i = 0; i < n; i++) {
    originalProfit += strategy[i] * prices[i];
  }

  const prefixPrices = new Array(n + 1).fill(0);
  for (let i = 0; i < n; i++) {
    prefixPrices[i + 1] = prefixPrices[i] + prices[i];
  }

  const prefixStrategy = new Array(n + 1).fill(0);
  for (let i = 0; i < n; i++) {
    prefixStrategy[i + 1] = prefixStrategy[i] + strategy[i] * prices[i];
  }

  let maxGain = 0;
  const halfK = k / 2;
  for (let i = 0; i <= n - k; i++) {
    const originalContribution = prefixStrategy[i + k] - prefixStrategy[i];
    const startSecond = i + halfK;
    const endSecond = i + k;
    const sumSecond = prefixPrices[endSecond] - prefixPrices[startSecond];
    const gain = sumSecond - originalContribution;
    if (gain > maxGain) {
      maxGain = gain;
    }
  }

  return originalProfit + Math.max(maxGain, 0);
}
